package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.AkeVerval;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.service.AkeVervalService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;

public class CachedAkeVervalService implements CachedService, AkeVervalService {

    @Autowired
    private AkeVervalService akeVervalService;

    private static final ThreadLocal<CachedAkeVervalBuffer> BUFFER = new ThreadLocal<>();

    public CachedAkeVervalService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public AkeVerval getByAardCodeExtensieAndDatum(AardKodeExtensie looncode, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedAkeVervalService.getByAardCodeExtensieAndDatum");
        CachedAkeVervalBuffer buffer = CachedAkeVervalService.getBuffer();
        AkeVerval result = buffer.get(looncode.getId());
        if (result == null && !buffer.containsKey(looncode.getId())) {
            result = akeVervalService.getByAardCodeExtensieOud(looncode);
            buffer.put(looncode.getId(), result);
        }
        if (result != null && result.getVervalDatum().compareTo(datum) >= 0) {
            result = null;
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }


    @Override
    public void clearCache() {
        CachedAkeVervalService.getBuffer().clear();
    }

    private static class CachedAkeVervalBuffer {

        private final Map<Integer, AkeVerval> akeOudBuffer = new HashMap<>();

        public AkeVerval get(Integer key) {
            return akeOudBuffer.get(key);
        }

        public void put(Integer key, AkeVerval akeOud) {
            akeOudBuffer.put(key, akeOud);
        }

        public boolean containsKey(Integer key) {
            return akeOudBuffer.containsKey(key);
        }

        public void clear() {
            akeOudBuffer.clear();
        }
    }

    private static CachedAkeVervalBuffer getBuffer() {
        CachedAkeVervalBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedAkeVervalBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public AkeVerval getByAardCodeExtensieOud(AardKodeExtensie looncode) {
        return akeVervalService.getByAardCodeExtensieOud(looncode);
    }

    @Override
    public Optional<AkeVerval> getVervallenAkeInInterval(AardKodeExtensie looncode, LocalDateInterval interval) {
        return akeVervalService.getVervallenAkeInInterval(looncode, interval);
    }

    @Override
    public List<AkeVerval> findAll() {
        return akeVervalService.findAll();
    }

    @Override
    public AkeVerval create(AkeVerval constant) {
        return akeVervalService.create(constant);
    }

    @Override
    public void update(AkeVerval constant) {
        akeVervalService.update(constant);
    }

    @Override
    public void delete(AkeVerval constant) {
        akeVervalService.delete(constant);
    }

    @Override
    public AkeVerval getById(Integer id) {
        return akeVervalService.getById(id);
    }

    @Override
    public AkeVerval getById(Integer id, String fetchFields) {
        return akeVervalService.getById(id, fetchFields);
    }

    @Override
    public AkeVerval getByCriteria(CriteriaBuilder cb) {
        return akeVervalService.getByCriteria(cb);
    }


    @Override
    public List<AkeVerval> findAll(String fetchFields) {
        return akeVervalService.findAll(fetchFields);
    }

    @Override
    public List<AkeVerval> findByCriteria(CriteriaBuilder cb) {
        return akeVervalService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return akeVervalService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, AkeVerval> cacheByCriteria(CriteriaBuilder cb) {
        return akeVervalService.cacheByCriteria(cb);
    }

    @Override
    public AkeVerval getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return akeVervalService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<AkeVerval> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return akeVervalService.findByCriteriaTemporalFree(cb);
    }
}
